const https = require('https');
const http = require('http');
const { URL } = require('url');
const { JSDOM } = require('jsdom');

const ALLOWED_DOMAINS = ['example.com', 'anotherdomain.com']; // Add allowed domains here
const BLOCKED_IP_RANGES = [
    /^10\./, // Private IP range
    /^172\.16\./, // Private IP range
    /^192\.168\./, // Private IP range
    /^127\.0\.0\.1$/, // Localhost
];

const isAllowedDomain = (hostname) => {
    return ALLOWED_DOMAINS.some(domain => hostname.endsWith(domain));
};

const isBlockedIP = (ip) => {
    return BLOCKED_IP_RANGES.some(range => range.test(ip));
};

const fetchMetadata = (url) => {
    return new Promise((resolve, reject) => {
        const parsedUrl = new URL(url);
        if (!isAllowedDomain(parsedUrl.hostname)) {
            return reject(new Error('Domain not allowed'));
        }

        const options = {
            method: 'GET',
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/58.0.3029.110 Safari/537.3'
            },
            maxRedirects: 0 // Control redirects
        };

        const request = parsedUrl.protocol === 'https:' ? https.request : http.request;

        request(parsedUrl, options, (res) => {
            const { statusCode } = res;
            if (statusCode >= 300 && statusCode < 400) {
                return reject(new Error('Redirects not allowed'));
            }

            const chunks = [];
            res.on('data', (chunk) => chunks.push(chunk));
            res.on('end', () => {
                const html = Buffer.concat(chunks).toString();
                const dom = new JSDOM(html);
                const document = dom.window.document;

                const title = document.querySelector('title') ? document.querySelector('title').textContent : '';
                const description = document.querySelector('meta[name="description"]') ? document.querySelector('meta[name="description"]').content : '';
                const ogTags = Array.from(document.querySelectorAll('meta[property^="og:"]')).reduce((acc, meta) => {
                    acc[meta.getAttribute('property')] = meta.getAttribute('content');
                    return acc;
                }, {});

                resolve({ title, description, ogTags });
            });
        }).on('error', (err) => {
            reject(err);
        }).end();
    });
};

module.exports = { fetchMetadata };